/**
 * @summary Get messages in a group
 */
export const getGetGroupMessagesUrl = (groupId: number) => {
  return `/api/groups/${groupId}/messages`;
};

export const getGroupMessages = async (
  groupId: number,
  options?: RequestInit,
): Promise<Message[]> => {
  return customFetch<Message[]>(getGetGroupMessagesUrl(groupId), {
    ...options,
    method: "GET",
  });
};

export const getGetGroupMessagesQueryKey = (groupId: number) => {
  return [`/api/groups/${groupId}/messages`] as const;
};

export const getGetGroupMessagesQueryOptions = <
  TData = Awaited<ReturnType<typeof getGroupMessages>>,
  TError = ErrorType<unknown>,
>(
  groupId: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getGroupMessages>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetGroupMessagesQueryKey(groupId);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getGroupMessages>>
  > = ({ signal }) => getGroupMessages(groupId, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!groupId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getGroupMessages>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetGroupMessagesQueryResult = NonNullable<
  Awaited<ReturnType<typeof getGroupMessages>>
>;
export type GetGroupMessagesQueryError = ErrorType<unknown>;

/**
 * @summary Get messages in a group
 */

export function useGetGroupMessages<
  TData = Awaited<ReturnType<typeof getGroupMessages>>,
  TError = ErrorType<unknown>,
>(
  groupId: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getGroupMessages>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetGroupMessagesQueryOptions(groupId, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
